import React from 'react';
import { Card, CardContent, Box, Typography, Stack, Chip } from '@mui/material';
import { TrendingUp, TrendingDown } from '@mui/icons-material';
import { LineChart } from '@mui/x-charts';
import response from './response.json';

interface Streak {
  days: number;
  bestStreak: number;
}

interface WordCount {
  today: number;
  average: number;
}

interface RecentEntry {
  date: string;
  title: string;
  words: number;
}

interface WidgetData {
  currentMood: string;
  streak: Streak;
  wordCount: WordCount;
  recentEntries: RecentEntry[];
}

export default function Widget() {
  const widgetData = response.data as WidgetData;
  const moodColor = widgetData.currentMood === 'Happy' ? '#FFC107' : '#FF5722';
  const isPositiveStreak = widgetData.streak.days >= widgetData.streak.bestStreak;

  return (
    <Card sx={{ width: 'fit-content', minWidth: 320, maxWidth: 450, bgcolor: '#FFFFFF' }} elevation={2}>
      <CardContent sx={{ p: 2 }}>
        <Stack spacing={2}>
          <Box>
            <Typography variant="h6" sx={{ color: moodColor }}>
              Mood Tracker
            </Typography>
            <Typography variant="body1" sx={{ color: moodColor }}>
              Current Mood: {widgetData.currentMood}
            </Typography>
          </Box>

          <Stack direction="row" spacing={1} alignItems="center">
            {isPositiveStreak ? (
              <TrendingUp sx={{ fontSize: 20, color: '#10B981' }} />
            ) : (
              <TrendingDown sx={{ fontSize: 20, color: '#EF4444' }} />
            )}
            <Typography variant="body2" sx={{ color: isPositiveStreak ? '#10B981' : '#EF4444' }}>
              Streak: {widgetData.streak.days} days
            </Typography>
            <Typography variant="caption" sx={{ color: 'text.secondary', ml: 1 }}>
              Best: {widgetData.streak.bestStreak} days
            </Typography>
          </Stack>

          <Box>
            <Typography variant="body2" sx={{ color: '#6B7280', mb: 0.5 }}>
              Today's Word Count
            </Typography>
            <Typography variant="h4" sx={{ fontWeight: 700, color: '#1F2937' }}>
              {widgetData.wordCount.today}
            </Typography>
            <Typography variant="caption" sx={{ color: 'text.secondary' }}>
              Average: {widgetData.wordCount.average}
            </Typography>
          </Box>

          <Stack spacing={1}>
            <Typography variant="body2" sx={{ color: '#6B7280' }}>
              Recent Entries
            </Typography>
            {widgetData.recentEntries.slice(0, 3).map((entry, index) => (
              <Box key={index}>
                <Typography variant="body2" sx={{ fontWeight: 500 }}>
                  {entry.title}
                </Typography>
                <Typography variant="caption" sx={{ color: 'text.secondary' }}>
                  {entry.date} - {entry.words} words
                </Typography>
              </Box>
            ))}
          </Stack>
        </Stack>
      </CardContent>
    </Card>
  );
}
